class Meal {
    private String cheese;
    public void setCheese(String c) { this.cheese = c; } // public setter!
}

Meal m = new Meal.Builder().cheese("cheddar").build();
m.setCheese("swiss"); // modified AFTER build! Builder was pointless.

goodCode:
class Meal {
    private final String cheese; // final -- can't change after construction
    // NO setter. Only getter.
    public String getCheese() { return cheese; }
}

badCode:
private Meal(Builder b) {
    this.toppings = b.toppings; // SHARED reference!
}
// After build:
builder.toppings.add("poison"); // corrupts the built meal!

goodCode:
private Meal(Builder b) {
    this.toppings = List.copyOf(b.toppings); // defensive copy!
}
// After build:
builder.toppings.add("poison"); // no effect on the meal

